import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, Legend, CartesianGrid } from "recharts";

function BusChart({ buses }) {
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    const now = new Date().toLocaleTimeString();

    const normalCount = buses.filter(bus => bus.status === "normal").length;
    const anomalyCount = buses.filter(bus => bus.status === "anomaly").length;
    const ghostCount = buses.filter(bus => bus.status === "ghost").length;

    setChartData(prev => [
      ...prev.slice(-9), // keep last 10 points
      { time: now, normal: normalCount, anomaly: anomalyCount, ghost: ghostCount },
    ]);
  }, [buses]);

  return (
    <LineChart width={400} height={200} data={chartData}>
      <CartesianGrid stroke="#ccc" />
      <XAxis dataKey="time" />
      <YAxis />
      <Tooltip />
      <Legend />
      <Line type="monotone" dataKey="normal" stroke="green" />
      <Line type="monotone" dataKey="anomaly" stroke="orange" />
      <Line type="monotone" dataKey="ghost" stroke="red" />
    </LineChart>
  );
}

export default BusChart;
